import { useState, useRef, useEffect } from 'react'
import { useParams } from 'react-router-dom'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const containerRef = useRef(null)

  const [selectedColor, setSelectedColor] = useState(
    product.colors[0]
  )

  const [selectedSize, setSelectedSize] = useState('M')

  const [uploadedLogo, setUploadedLogo] = useState(null)

  const [uploadedFile, setUploadedFile] = useState(null)

  const [logoSize, setLogoSize] = useState(180)

  const [isDragging, setIsDragging] = useState(false)

  const [activePreset, setActivePreset] = useState('front')

  const [logoPosition, setLogoPosition] = useState({
    x: 50,
    y: 42
  })

  const [customerName, setCustomerName] = useState('')

  const [customerEmail, setCustomerEmail] = useState('')

  const [customerPhone, setCustomerPhone] = useState('')

  const [quantity, setQuantity] = useState('24')

  const [notes, setNotes] = useState('')

  const [showSuccess, setShowSuccess] = useState(false)

  const [showSummary, setShowSummary] = useState(false)

  useEffect(() => {

    const savedQuote =
      localStorage.getItem('latestQuote')

    if (savedQuote) {

      const parsed =
        JSON.parse(savedQuote)

      setCustomerName(parsed.customerName || '')
      setCustomerEmail(parsed.customerEmail || '')
      setCustomerPhone(parsed.customerPhone || '')
      setNotes(parsed.notes || '')
      setQuantity(parsed.quantity || '24')
    }

  }, [])

  useEffect(() => {

    const handleKeyDown = (e) => {

      const step = 1

      if (e.key === 'ArrowUp') {

        setLogoPosition(prev => ({
          ...prev,
          y: prev.y - step
        }))
      }

      if (e.key === 'ArrowDown') {

        setLogoPosition(prev => ({
          ...prev,
          y: prev.y + step
        }))
      }

      if (e.key === 'ArrowLeft') {

        setLogoPosition(prev => ({
          ...prev,
          x: prev.x - step
        }))
      }

      if (e.key === 'ArrowRight') {

        setLogoPosition(prev => ({
          ...prev,
          x: prev.x + step
        }))
      }

      if (e.key === '[') {

        setLogoSize(prev =>
          Math.max(prev - 5, 60)
        )
      }

      if (e.key === ']') {

        setLogoSize(prev =>
          Math.min(prev + 5, 400)
        )
      }
    }

    window.addEventListener(
      'keydown',
      handleKeyDown
    )

    return () => {

      window.removeEventListener(
        'keydown',
        handleKeyDown
      )
    }

  }, [])

  const handleUpload = (e) => {

    const file = e.target.files[0]

    if (file) {

      setUploadedFile(file)

      setUploadedLogo(
        URL.createObjectURL(file)
      )
    }
  }

  const handleMouseMove = (e) => {

    if (!isDragging) return

    const rect =
      containerRef.current.getBoundingClientRect()

    const x =
      ((e.clientX - rect.left) / rect.width) * 100

    const y =
      ((e.clientY - rect.top) / rect.height) * 100

    setLogoPosition({
      x,
      y
    })
  }

  const handleMouseUp = () => {
    setIsDragging(false)
  }

  const setPreset = (type) => {

    setActivePreset(type)

    if (type === 'front') {
      setLogoPosition({ x: 50, y: 42 })
      setLogoSize(180)
    }

    if (type === 'left-chest') {
      setLogoPosition({ x: 38, y: 30 })
      setLogoSize(90)
    }

    if (type === 'oversized') {
      setLogoPosition({ x: 50, y: 45 })
      setLogoSize(320)
    }

    if (type === 'back') {
      setLogoPosition({ x: 50, y: 42 })
      setLogoSize(260)
    }

    if (type === 'sleeve') {
      setLogoPosition({ x: 72, y: 33 })
      setLogoSize(70)
    }
  }

  const submitQuote = () => {

    if (
      !customerName ||
      !customerEmail ||
      !customerPhone
    ) {

      alert('Please complete required fields')

      return
    }

    const quoteData = {

      product: product.name,

      color: selectedColor.name,

      size: selectedSize,

      quantity,

      placement: activePreset,

      logoX: Math.round(logoPosition.x),

      logoY: Math.round(logoPosition.y),

      logoSize,

      customerName,

      customerEmail,

      customerPhone,

      notes,

      uploadedFile: uploadedFile
        ? uploadedFile.name
        : 'No File'
    }

    console.log(quoteData)

    localStorage.setItem(
      'latestQuote',
      JSON.stringify(quoteData)
    )

    setShowSuccess(true)

    setShowSummary(true)

    setTimeout(() => {

      setShowSuccess(false)

    }, 4000)
  }

  return (

    <div
      className="h-screen bg-black text-white px-4 py-4 overflow-hidden"
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
    >

      {showSuccess && (

        <div className="fixed top-4 right-4 z-50 bg-yellow-500 text-black px-5 py-3 rounded-xl font-black text-sm">

          Quote Request Submitted

        </div>

      )}

      <div className="max-w-[1850px] mx-auto grid grid-cols-1 xl:grid-cols-2 gap-6 h-full items-center">


        <div
          ref={containerRef}
          className="bg-[#111] border border-[#222] rounded-[30px] p-2 flex items-center justify-center relative overflow-hidden h-[88vh]"
        >

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[520px] relative z-10"
          />

          {uploadedLogo && (

            <img
              src={uploadedLogo}
              alt="logo"
              onMouseDown={() => setIsDragging(true)}
              className="absolute z-20 opacity-95 select-none"
              style={{
                width: `${logoSize}px`,
                top: `${logoPosition.y}%`,
                left: `${logoPosition.x}%`,
                transform: 'translate(-50%, -50%)',
                cursor: isDragging ? 'grabbing' : 'grab'
              }}
              draggable={false}
            />

          )}

        </div>


        <div className="flex flex-col justify-center h-[88vh]">

          <p className="text-yellow-500 tracking-[0.25em] uppercase text-[9px] mb-2">
            Inspired By God Print Division
          </p>

          <h1 className="text-4xl font-black leading-none mb-2">
            {product.name}
          </h1>

          <p className="text-xl text-yellow-500 mb-5">
            Starting at ${product.price}
          </p>


          <div className="grid grid-cols-2 gap-3 mb-4">

            {[
              'front',
              'left-chest',
              'oversized',
              'back',
              'sleeve'
            ].map((item) => (

              <button
                key={item}
                onClick={() => setPreset(item)}
                className={`px-3 py-3 rounded-xl text-xs font-black transition ${
                  activePreset === item
                    ? 'bg-yellow-500 text-black'
                    : 'border border-[#333] text-white'
                }`}
              >
                {item}
              </button>

            ))}

          </div>


          <div className="flex gap-2 mb-4">

            {product.colors.map((color) => (

              <button
                key={color.name}
                onClick={() => setSelectedColor(color)}
                className={`w-10 h-10 rounded-full border-4 ${
                  selectedColor.name === color.name
                    ? 'border-yellow-500'
                    : 'border-white'
                }`}
                style={{
                  backgroundColor: color.hex
                }}
              />

            ))}

          </div>


          <div className="grid grid-cols-3 gap-2 mb-4">

            {['S','M','L','XL','2XL','3XL'].map((size) => (

              <button
                key={size}
                onClick={() => setSelectedSize(size)}
                className={`py-2 rounded-lg text-xs font-bold ${
                  selectedSize === size
                    ? 'bg-yellow-500 text-black'
                    : 'border border-[#333]'
                }`}
              >
                {size}
              </button>

            ))}

          </div>


          <div className="grid grid-cols-2 gap-3 mb-3">

            <input
              type="number"
              placeholder="Quantity"
              value={quantity}
              onChange={(e) =>
                setQuantity(e.target.value)
              }
              className="bg-[#111] border border-[#222] rounded-xl p-3 text-sm text-white"
            />

            <input
              type="text"
              placeholder="Phone Number"
              value={customerPhone}
              onChange={(e) =>
                setCustomerPhone(e.target.value)
              }
              className="bg-[#111] border border-[#222] rounded-xl p-3 text-sm text-white"
            />

          </div>


          <input
            type="text"
            placeholder="Your Name"
            value={customerName}
            onChange={(e) =>
              setCustomerName(e.target.value)
            }
            className="w-full bg-[#111] border border-[#222] rounded-xl p-3 text-sm text-white mb-3"
          />


          <input
            type="email"
            placeholder="Email Address"
            value={customerEmail}
            onChange={(e) =>
              setCustomerEmail(e.target.value)
            }
            className="w-full bg-[#111] border border-[#222] rounded-xl p-3 text-sm text-white mb-3"
          />


          <input
            type="file"
            accept="image/png,image/jpeg"
            onChange={handleUpload}
            className="w-full bg-[#111] border border-[#222] rounded-xl p-3 text-sm mb-3"
          />


          <div className="mb-3">

            <div className="flex justify-between items-center mb-2">

              <p className="text-xs text-white/70">
                Logo Size
              </p>

              <p className="text-xs text-yellow-500 font-bold">
                {logoSize}px
              </p>

            </div>

            <input
              type="range"
              min="60"
              max="400"
              value={logoSize}
              onChange={(e) =>
                setLogoSize(e.target.value)
              }
              className="w-full"
            />

          </div>


          <div className="grid grid-cols-2 gap-3 mb-3">

            <div className="bg-[#111] border border-[#222] rounded-xl p-3 text-xs">

              X:
              <span className="text-yellow-500 ml-2 font-bold">
                {Math.round(logoPosition.x)}
              </span>

            </div>

            <div className="bg-[#111] border border-[#222] rounded-xl p-3 text-xs">

              Y:
              <span className="text-yellow-500 ml-2 font-bold">
                {Math.round(logoPosition.y)}
              </span>

            </div>

          </div>


          <p className="text-[10px] text-white/50 mb-3">
            Arrow Keys = Move Logo • [ ] = Resize Logo
          </p>


          <textarea
            rows="2"
            placeholder="Additional Notes"
            value={notes}
            onChange={(e) =>
              setNotes(e.target.value)
            }
            className="w-full bg-[#111] border border-[#222] rounded-xl p-3 text-sm text-white mb-3"
          />


          <button
            onClick={submitQuote}
            className="w-full bg-yellow-500 text-black py-4 rounded-2xl text-sm font-black"
          >

            REQUEST QUOTE

          </button>


          {showSummary && (

            <div className="mt-4 bg-[#111] border border-[#222] rounded-2xl p-4 text-xs">

              <div className="space-y-2">

                <p>
                  Product: {product.name}
                </p>

                <p>
                  Color: {selectedColor.name}
                </p>

                <p>
                  Size: {selectedSize}
                </p>

                <p>
                  Quantity: {quantity}
                </p>

                <p>
                  Placement: {activePreset}
                </p>

                <p>
                  Logo Size: {logoSize}px
                </p>

              </div>

            </div>

          )}

        </div>

      </div>

    </div>

  )
}
